var goExample = `package main

import (
	"fmt"
	"net/http"

	"github.com/go-chi/chi/v5"
	"github.com/laenen-partners/dsx/ds"
	"github.com/starfederation/datastar-go/datastar"
)

func main() {
	r := chi.NewRouter()

	r.Get("/greet", func(w http.ResponseWriter, r *http.Request) {
		sse := datastar.NewSSE(w, r)
		ds.Send.Toast(sse, ds.ToastSuccess, "Hello, World!")
	})

	fmt.Println("Server started on :3000")
	http.ListenAndServe(":3000", r)
}`

var templExample = `templ UserCard(name string, role string, active bool) {
	@card.Card() {
		@card.Body() {
			@card.Title() {
				{ name }
			}
			<p class="text-sm text-base-content/70">{ role }</p>
			if active {
				@badge.Badge(badge.Props{Variant: badge.VariantSuccess}) {
					Active
				}
			}
			<div class="card-actions mt-4">
				<button
					class="btn btn-primary btn-sm"
					{ ds.OnClick(ds.GetOnce(wctx.APIPath("/user/details")))... }
				>
					View Details
				</button>
			</div>
		}
	}
}`

